let status = "flagged"; // Default status
let matchedRow = null;

// --- Helper: Convert "11-Mar-26" (or similar) to "YYYY-MM-DD" ---
function normalizeStatementDate(dateStr) {
  if (!dateStr) return null;

  // Clean potential spaces
  const cleanStr = dateStr.trim();
  const parts = cleanStr.split("-");
  if (parts.length !== 3) return cleanStr; // Return as-is if format is unexpected

  const day = parts[0].padStart(2, "0");
  const monthAbbr = parts[1].toLowerCase();
  let year = parts[2];

  // Map English month abbreviations
  const months = {
    jan: "01",
    feb: "02",
    mar: "03",
    apr: "04",
    may: "05",
    jun: "06",
    jul: "07",
    aug: "08",
    sep: "09",
    oct: "10",
    nov: "11",
    dec: "12",
  };

  const month = months[monthAbbr] || "01";

  // Turn 2-digit years (e.g. "26") into 4-digit years (e.g. "2026")
  if (year.length === 2) {
    year = "20" + year;
  }

  return `${year}-${month}-${day}`;
}

// --- Helper: Clean Amount formatting (converts "10,000" to 10000) ---
function cleanAmount(val) {
  if (val === undefined || val === null) return 0;
  // Strip commas, spaces and convert to a clean float
  return parseFloat(String(val).replace(/,/g, "").trim()) || 0;
}

// --- Helper: Check if name parts match inside detail string ---
function matchesSenderName(detailText, extractedName) {
  if (!detailText || !extractedName) return false;

  const detailLower = detailText.toLowerCase();
  const nameLower = extractedName.toLowerCase();

  // 1. Try a direct match first
  if (detailLower.includes(nameLower)) return true;

  // 2. Fallback: Check if individual name parts (e.g., "AQEEL" and "TANVEER") exist to handle middle names/omissions
  const nameParts = nameLower.split(/\s+/).filter((part) => part.length > 2); // only use names longer than 2 chars
  if (nameParts.length === 0) return false;

  // If at least two major name parts are found in the statement row, mark it as matching
  const matchCount = nameParts.filter((part) =>
    detailLower.includes(part),
  ).length;
  return matchCount >= Math.min(nameParts.length, 2);
}

// 3. Loop through your live bank statement rows to find a match
